function LogTerminal({logs}){const ref=useRef(null);useEffect(()=>{ref.current?.scrollTo({top:ref.current.scrollHeight,behavior:"smooth"});},[logs.length]);const lc={INFO:"#0077a8",WARN:"#b37400",ERROR:C.error,TOOL:"#5a67d8",LLM:"#b83280",HITL:C.purple};return (<div ref={ref} style={{background:"#1a1a2e",borderRadius:10,padding:16,fontFamily:C.fontMono,fontSize:11,lineHeight:1.8,maxHeight:400,overflowY:"auto"}}>{logs.length===0?<div style={{color:"#6b7280"}}>Waiting...</div>:logs.map((l,i)=>(<div key={i} style={{display:"flex",gap:10,animation:"fadeIn 0.3s ease"}}><span style={{color:"#6b7280",flexShrink:0}}>{l.ts}</span><span style={{color:lc[l.lv]||"#9ca3af",flexShrink:0,width:36,textAlign:"right",fontWeight:600}}>{l.lv}</span><span style={{color:l.lv==="WARN"?"#fbbf24":l.lv==="ERROR"?"#f87171":"#e5e7eb"}}>{l.m}</span></div>))}</div>);}
function DT({columns,rows}){return (<div style={{overflowX:"auto",borderRadius:8,border:`1px solid ${C.border}`}}><table style={{width:"100%",borderCollapse:"collapse",fontFamily:C.fontMono,fontSize:12}}><thead><tr style={{background:C.bgMuted}}>{columns.map(c=><th key={c} style={{padding:"10px 14px",textAlign:"left",color:C.textSecondary,fontWeight:700,fontSize:11,fontFamily:C.fontSans,borderBottom:`1px solid ${C.border}`}}>{c}</th>)}</tr></thead><tbody>{rows}</tbody></table></div>);}
function JsonInspector({value,depth=0}){
  const pad=depth*12;
  if(value===null)return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.textMuted}}>null</span>;
  if(Array.isArray(value)){
    if(value.length===0)return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.textMuted}}>[]</span>;
    return (<div style={{display:"flex",flexDirection:"column",gap:6,paddingLeft:pad}}>{value.map((item,idx)=>(<div key={idx} style={{display:"flex",alignItems:"flex-start",gap:6}}><span style={{fontFamily:C.fontMono,fontSize:11,color:C.textMuted,minWidth:22}}>[{idx}]</span><JsonInspector value={item} depth={depth+1}/></div>))}</div>);
  }
  if(typeof value==="object"){
    const entries=Object.entries(value);
    if(entries.length===0)return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.textMuted}}>{"{}"}</span>;
    return (<div style={{display:"flex",flexDirection:"column",gap:6,paddingLeft:pad}}>{entries.map(([key,next])=>(<div key={key} style={{display:"flex",alignItems:"flex-start",gap:8}}><span style={{fontFamily:C.fontMono,fontSize:11,color:C.attBlueDark,minWidth:140,maxWidth:240,wordBreak:"break-word"}}>{key}</span><JsonInspector value={next} depth={depth+1}/></div>))}</div>);
  }
  if(typeof value==="string")return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.success,wordBreak:"break-word"}}>{`"${value}"`}</span>;
  if(typeof value==="number")return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.purple}}>{String(value)}</span>;
  if(typeof value==="boolean")return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.warning}}>{String(value)}</span>;
  return <span style={{fontFamily:C.fontMono,fontSize:11,color:C.textPrimary}}>{String(value)}</span>;
}
